fn input() -> u8 {
    let mut buf = String::new();
    std::io::stdin().read_line(&mut buf).unwrap();
    buf.trim().parse().unwrap()
}

fn input_split() -> Vec<u8> {
    let mut buf = String::new();
    std::io::stdin().read_line(&mut buf).unwrap();
    buf.trim()
        .split_whitespace()
        .map(|elem| elem.parse().unwrap())
        .collect()
}

fn main() {
    let mut k = input();
    let mut months = input_split();
    months.sort_unstable_by(|a, b| b.cmp(&a));

    let mut count = 0;

    for month in months {
        if k == 0 {
            break;
        }
        count += 1;
        if month > k {
            break;
        } else {
            k -= month;
        }
    }

    if count == 12 && k != 0 {
        print!("-1")
    } else {
        print!("{}", count)
    }
}
